    it 'Tests required X-API-Key header with valid value' do
      require 'net/http'
      require 'uri'
      require 'json'
      _uri = URI.parse("#{mock_server_url}/fixtures/x_api_key_required_header_success")
      _http = Net::HTTP.new(_uri.host, _uri.port)
      _req = Net::HTTP::GET  .new(_uri.request_uri)
      _req['key'] = 'secret'
      response = _http.request(_req)
      expect(response.code.to_i).to eq(200)
      _body = JSON.parse(response.body)
      expect(_body).to eq({ 'username' => 'secret' })
    end
  end
end
